### Purpose
Create comprehensive unit tests for the E2E logging infrastructure in tests/util/e2e_log.rs to ensure the logging utilities work correctly before using them in E2E tests.

### Required Implementation

1. **Add unit tests to tests/util/e2e_log.rs:**

```rust
#[cfg(test)]
mod tests {
    use super::*;
    use std::fs;
    use tempfile::TempDir;

    #[test]
    fn test_run_id_generation() {
        let id1 = E2eLogger::generate_run_id();
        let id2 = E2eLogger::generate_run_id();

        // Format: YYYYMMDD_HHMMSS_random
        assert!(id1.len() > 15, "Run ID too short");
        assert_ne!(id1, id2, "Run IDs should be unique");
    }

    #[test]
    fn test_logger_creates_file() {
        let temp = TempDir::new().unwrap();
        std::env::set_var("E2E_LOG_DIR", temp.path());
        std::env::set_var("E2E_LOG", "1");

        let logger = E2eLogger::new("rust").unwrap();

        // File should be created
        let files: Vec<_> = fs::read_dir(temp.path()).unwrap().collect();
        assert!(!files.is_empty(), "Log file should be created");
    }

    #[test]
    fn test_run_start_event_format() {
        let temp = TempDir::new().unwrap();
        std::env::set_var("E2E_LOG_DIR", temp.path());
        std::env::set_var("E2E_LOG", "1");

        let logger = E2eLogger::new("rust").unwrap();
        logger.run_start().unwrap();

        // Read and validate
        let content = read_last_log_line(&temp);
        let json: serde_json::Value = serde_json::from_str(&content).unwrap();

        assert_eq!(json["event"], "run_start");
        assert!(json["ts"].is_string());
        assert!(json["run_id"].is_string());
        assert_eq!(json["runner"], "rust");
        assert!(json["env"].is_object());
    }

    #[test]
    fn test_phase_tracker_phases() {
        let temp = TempDir::new().unwrap();
        std::env::set_var("E2E_LOG_DIR", temp.path());
        std::env::set_var("E2E_LOG", "1");

        let tracker = PhaseTracker::new("test_suite", "test_name");

        tracker.phase("setup", "Setting up", || {
            std::thread::sleep(std::time::Duration::from_millis(10));
        });

        tracker.complete();

        // Verify phase_start and phase_end events
        let content = read_all_log_lines(&temp);
        assert!(content.contains("phase_start"));
        assert!(content.contains("phase_end"));
        assert!(content.contains("duration_ms"));
    }

    #[test]
    fn test_metrics_format() {
        let temp = TempDir::new().unwrap();
        std::env::set_var("E2E_LOG_DIR", temp.path());
        std::env::set_var("E2E_LOG", "1");

        let tracker = PhaseTracker::new("test_suite", "test_name");

        tracker.metrics("test_metric", &E2ePerformanceMetrics {
            duration_ms: 100,
            items_processed: Some(42),
            memory_bytes: Some(1024),
            throughput_per_sec: Some(4.2),
        });

        let content = read_last_log_line(&temp);
        let json: serde_json::Value = serde_json::from_str(&content).unwrap();

        assert_eq!(json["event"], "metrics");
        assert_eq!(json["name"], "test_metric");
        assert_eq!(json["metrics"]["duration_ms"], 100);
        assert_eq!(json["metrics"]["items_processed"], 42);
    }

    #[test]
    fn test_error_context_serialization() {
        let error = E2eError {
            message: "Test failed".to_string(),
            code: Some("TEST_ERROR".to_string()),
            context: Some(E2eErrorContext {
                command: Some("cass index".to_string()),
                cwd: Some("/tmp/test".to_string()),
                exit_code: Some(1),
                stdout: Some("output".to_string()),
                stderr: Some("error".to_string()),
                env: None,
            }),
        };

        let json = serde_json::to_value(&error).unwrap();
        assert_eq!(json["message"], "Test failed");
        assert_eq!(json["context"]["command"], "cass index");
    }
}
```

