### Deployment Flow

```rust
pub async fn deploy_to_cloudflare(
    site_dir: &Path,
    project_name: &str,
    config: &CloudflareConfig,
) -> Result<DeploymentResult, DeployError> {
    // 1. Create project if needed
    if !project_exists(project_name).await? {
        create_project(project_name).await?;
    }

    // 2. Deploy using wrangler
    let output = std::process::Command::new("wrangler")
        .args(["pages", "deploy", site_dir.to_str().unwrap()])
        .arg("--project-name")
        .arg(project_name)
        .output()?;

    if !output.status.success() {
        return Err(DeployError::WranglerFailed(
            String::from_utf8_lossy(&output.stderr).to_string()
        ));
    }

    // 3. Parse deployment URL from output
    let url = parse_deployment_url(&output.stdout)?;

    Ok(DeploymentResult {
        url,
        project_name: project_name.to_string(),
        deployed_at: Utc::now(),
    })
}
```

